const item = $input.first();
const body = item.json.body || item.json;
const binary = item.binary || {};

const binaryKeys = Object.keys(binary);

// ── Detect room binary (prefer key 'room', fallback first key) ──
let roomFieldName = null;
if (binary.room) roomFieldName = 'room';
else if (binaryKeys[0]) roomFieldName = binaryKeys[0];

// ── Detect sketch binary (prefer key 'sketch', fallback second key) ──
let sketchFieldName = null;
if (binary.sketch) sketchFieldName = 'sketch';
else if (binaryKeys.length > 1) sketchFieldName = binaryKeys.find(k => k !== roomFieldName) || null;
else if (binaryKeys[0] && binaryKeys[0] !== roomFieldName) sketchFieldName = binaryKeys[0];

if (!roomFieldName || !binary[roomFieldName]) {
  return [{ json: { valid: false, error: "Missing room image (binary field 'room')" } }];
}
if (!sketchFieldName || !binary[sketchFieldName]) {
  return [{ json: { valid: false, error: "Missing sketch image (binary field 'sketch')" } }];
}

// ── File size validation (20 MB max) ──
const MAX_BYTES = 20 * 1024 * 1024;
const roomBin   = binary[roomFieldName];
const sketchBin = binary[sketchFieldName];

const roomBytes   = roomBin.fileSize   ?? Math.ceil((roomBin.data.length   * 3) / 4);
const sketchBytes = sketchBin.fileSize ?? Math.ceil((sketchBin.data.length * 3) / 4);

if (roomBytes > MAX_BYTES) {
  return [{ json: { valid: false, error: `Room image too large (${(roomBytes/1024/1024).toFixed(1)} MB). Max 20 MB.` } }];
}
if (sketchBytes > MAX_BYTES) {
  return [{ json: { valid: false, error: `Sketch image too large (${(sketchBytes/1024/1024).toFixed(1)} MB). Max 20 MB.` } }];
}

// ── Parse text fields ──
const prompt = (body.prompt || '').trim();
const style  = (body.style  || 'moderne').trim();

let dimensions = {};
let materials  = {};
try { dimensions = JSON.parse(body.dimensions || '{}'); } catch(e) { dimensions = {}; }
try { materials  = JSON.parse(body.materials  || '{}'); } catch(e) { materials  = {}; }

if (!dimensions.width || !dimensions.depth || !dimensions.height) {
  return [{ json: { valid: false, error: 'Invalid or missing dimensions. Expected JSON: {"width":"3","depth":"4","height":"2.6"}' } }];
}

// ── Build prompt ──
const parts = [
  `Rendu photoréaliste cuisine ${style}, qualité 4K ultra, visualisation architecturale professionnelle`,
  prompt,
  materials.description ? `Matériaux et finitions: ${materials.description}` : '',
  `Pièce: ${dimensions.width}m largeur × ${dimensions.depth}m profondeur × ${dimensions.height}m hauteur`,
  "éclairage naturel, hyperréaliste, photographie d'intérieur de luxe, détail précis"
].filter(s => s && s.trim());

const negativePrompt = "flou, basse qualité, distordu, déformé, laid, sombre, amateur, surexposé, dessin, cartoon, 3D low-poly";

// ── Generate job ID ──
const jobId = Date.now().toString(36) + Math.random().toString(36).slice(2, 9);

// ── Build data URIs ──
const roomUri   = `data:${roomBin.mimeType   || 'image/jpeg'};base64,${roomBin.data}`;
const sketchUri = `data:${sketchBin.mimeType || 'image/jpeg'};base64,${sketchBin.data}`;

return [{ json: {
  valid:          true,
  jobId,
  fullPrompt:     parts.join('. '),
  negativePrompt,
  roomUri,
  sketchUri,
  roomFieldName,
  sketchFieldName,
  style,
  dimensionsRaw:  body.dimensions || '{}',
  materialsRaw:   body.materials  || '{}',
} }];

// Supabase POST response overwrites $json — restore data from Normalize & Validate
const prep = $('Normalize & Validate').first().json;

return [{ json: {
  jobId:          prep.jobId,
  fullPrompt:     prep.fullPrompt,
  negativePrompt: prep.negativePrompt,
  roomUri:        prep.roomUri,
  sketchUri:      prep.sketchUri,
  roomFieldName:  prep.roomFieldName,
  sketchFieldName: prep.sketchFieldName,
} }];

const item       = $input.first();
const prediction = item.json;
const jobId      = $('Normalize & Validate').first().json.jobId;

if (!prediction || !prediction.id) {
  throw new Error(`Replicate did not return a prediction ID. Response: ${JSON.stringify(prediction)}`);
}

return [{ json: {
  jobId,
  replicateId:     prediction.id,
  replicateStatus: prediction.status,
  outputUrl:       Array.isArray(prediction.output) ? prediction.output[0] : (prediction.output ?? null),
  replicateError:  prediction.error ?? null,
} }];
